async function sendToHubSpot(form) {
    const phoneInput = form.find('input[name="phone-number"]');

    const phone = phoneInput.length
        ? (phoneInput.closest(".iti").find(".iti__selected-dial-code").text() || "") +
          (phoneInput.val()?.trim() || "")
        : "";

    const params = new URLSearchParams(window.location.search);
    
    const payload = {
        fields: [
            { name: "firstname", value: form.find('[name="name"]').val()?.trim() || "" },
            { name: "company", value: form.find('[name="company-name"]').val()?.trim() || "" },
            { name: "email", value: form.find('[name="email"]').val()?.trim() || "" },
            { name: "phone", value: phone },
            { name: "industry", value: form.find('[name="industry"]').val()?.trim() || "" },
            { name: "country", value: form.find('[name="country"]').val()?.trim() || "" },
            { name: "product_count", value: form.find('[name="product-count"]').val()?.trim() || "" },
            { name: "company_size", value: form.find('[name="company-size"]').val()?.trim() || "" },
            { name: "customization_level", value: form.find('[name="customization-level"]').val()?.trim() || "" },
            { name: "product_references", value: form.find('[name="product-references"]').val()?.trim() || "" },
            { name: "use_case", value: form.find('[name="use-case"]').val()?.trim() || "" },
            { name: "referral_source", value: form.find('[name="referral-source"]').val()?.trim() || "" },
            { name: "additional_info", value: form.find('[name="additional-info"]').val()?.trim() || "" },
            { name: "landing_source", value: window.location.pathname },
            { name: "utm_source", value: params.get("utm_source") || "" },
            { name: "utm_medium", value: params.get("utm_medium") || "" },
            { name: "utm_campaign", value: params.get("utm_campaign") || "" },
            { name: "utm_content", value: params.get("utm_content") || "" },
            { name: "utm_term", value: params.get("utm_term") || "" },
            { name: "gclid", value: params.get("gclid") || "" }
        ]
    };

    const response = await fetch(
        "https://api-eu1.hsforms.com/submissions/v3/integration/submit/147624114/05938e94-1a8f-41db-b9f7-90e27075a8d8",
        {
            method: "POST",
            headers: {
                "Content-Type": "application/json"
            },
            body: JSON.stringify(payload)
        }
    );

    if (!response.ok) {
        throw new Error(await response.text());
    }
}
